import java.util.Scanner;

public class SecureBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a string: ");
        String userInput = scanner.nextLine().trim(); // Read a full line of input and trim any leading or trailing whitespace

        int maxLength = 10; // Maximum allowed length for the buffer
        char[] buffer = new char[maxLength];

        // Ensure that the input does not exceed the maximum length
        if (userInput.length() > maxLength) {
            userInput = userInput.substring(0, maxLength); // Truncate input if it exceeds maxLength
        }

        userInput.getChars(0, userInput.length(), buffer, 0);

        System.out.println("Buffer content: " + new String(buffer));
    }
}

